import sys
from collections import defaultdict


def get_z(s):
    z = [0] * len(s)
    l, r = 0, 0
    for i in range(1, len(s)):
        if i <= r:
            z[i] = min(r - i + 1, z[i - l])
        while i + z[i] < len(s) and s[z[i]] == s[i + z[i]]:
            z[i] += 1
        if i + z[i] - 1 > r:
            l, r = i, i + z[i] - 1
    return z


def get_count_of_occurrences(s, t):
    count = 0
    z_t = get_z(t + "#" + s)
    for i in range(len(z_t)):
        if z_t[i] == len(t):
            count += 1
    return count


def get_occurrences(s, t, l, r):
    count = 0
    z_t = get_z(t + "#" + s[l - 1:r])
    for i in range(len(z_t)):
        if z_t[i] == len(t) and s[l - 1 + i:l - 1 + i + len(t)] == t:
            count += 1
    return count


